UPDATE pilot_steps SET status='done', completed_at=now(), summary='Enforcement bloc ajouté au system prompt (pre-flight styles.css, hero image auto, patterns sectoriels obligatoires, mobile-first 390x844, animations par défaut, dark mode testé via tokens).' WHERE category_id IN (SELECT id FROM pilot_categories WHERE title='🎨 Qualité visuelle (Lovable-grade design)') AND status='todo';
UPDATE pilot_categories SET status='done', updated_at=now() WHERE title='🎨 Qualité visuelle (Lovable-grade design)' AND NOT EXISTS (SELECT 1 FROM pilot_steps WHERE category_id=pilot_categories.id AND status!='done');